120→#[derive(Debug, Clone, Copy, PartialEq)]
121→pub enum ToolEffect {
122→    Pure,
123→    Mutating,
124→}
125→
126→pub fn tool_effect(name: &str) -> ToolEffect {
127→    match name {
128→        "Read" | "Glob" | "Grep" => ToolEffect::Pure,
129→        "Bash" | "Edit" => ToolEffect::Mutating,
130→        _ => ToolEffect::Mutating,
131→    }
132→}
133→
134→/// Dispatch a tool call by name. Returns Ok(output) or Err(error_message).
135→/// Bash gets a streaming callback; other tools don't need one.
136→pub fn dispatch_tool(
137→    name: &str,
138→    input: &Value,
139→    stream_cb: &mut dyn FnMut(&str),
140→) -> Result<String, String> {
141→    match name {
142→        "Read" => read_exec(input),
143→        "Glob" => glob_exec(input),
144→        "Bash" => bash_exec(input, stream_cb),
145→        "Edit" => edit_exec(input),
146→        "Grep" => grep_exec(input),
147→        _ => Err(format!("Unknown tool: {name}")),
148→    }
149→}
