151→fn read_exec(input: &Value) -> Result<String, String> {
152→    let file_path = input["file_path"]
153→        .as_str()
154→        .ok_or("Missing required parameter: file_path")?;
155→
156→    let path = Path::new(file_path);
157→    if !path.exists() {
158→        return Err(format!("File not found: {file_path}"));
159→    }
160→
161→    let metadata =
162→        std::fs::metadata(path).map_err(|e| format!("Cannot read file metadata: {e}"))?;
163→    if metadata.len() > 1_048_576 {
164→        return Err(format!(
165→            "File too large: {} bytes (limit: 1MB)",
166→            metadata.len()
167→        ));
168→    }
169→
170→    let content = std::fs::read(path).map_err(|e| format!("Cannot read file: {e}"))?;
171→
172→    // Check for binary content (NUL bytes in first 8KB)
173→    let check_len = content.len().min(8192);
174→    if content[..check_len].contains(&0) {
175→        return Ok(format!(
176→            "[Binary file: {file_path}, {} bytes]",
177→            content.len()
178→        ));
179→    }
180→
181→    String::from_utf8(content).map_err(|_| format!("File contains invalid UTF-8: {file_path}"))
182→}
