374→fn edit_exec(input: &Value) -> Result<String, String> {
375→    let file_path = input["file_path"]
376→        .as_str()
377→        .ok_or("Missing required parameter: file_path")?;
378→    let old_str = input["old_str"]
379→        .as_str()
380→        .ok_or("Missing required parameter: old_str")?;
381→    let new_str = input["new_str"]
382→        .as_str()
383→        .ok_or("Missing required parameter: new_str")?;
384→    let replace_all = input["replace_all"].as_bool().unwrap_or(false);
385→
386→    let path = Path::new(file_path);
387→
388→    // Empty old_str: create file (if missing) or append (if exists)
389→    if old_str.is_empty() {
390→        if path.exists() {
391→            // Append
392→            let mut content =
393→                std::fs::read_to_string(path).map_err(|e| format!("Cannot read file: {e}"))?;
394→            content.push_str(new_str);
395→            std::fs::write(path, &content).map_err(|e| format!("Cannot write file: {e}"))?;
396→            return Ok(format!("Appended to {file_path}"));
397→        } else {
398→            // Create with parent dirs
399→            if let Some(parent) = path.parent() {
400→                std::fs::create_dir_all(parent)
401→                    .map_err(|e| format!("Cannot create directories: {e}"))?;
402→            }
403→            std::fs::write(path, new_str).map_err(|e| format!("Cannot create file: {e}"))?;
404→            return Ok(format!("Created {file_path}"));
405→        }
406→    }
407→
408→    // Normal edit: read, find, replace
409→    let content = std::fs::read_to_string(path).map_err(|e| format!("Cannot read file: {e}"))?;
410→
411→    let metadata = std::fs::metadata(path).map_err(|e| format!("Cannot read metadata: {e}"))?;
412→    if metadata.len() > 102_400 {
413→        return Err(format!(
414→            "File too large for edit: {} bytes (limit: 100KB)",
415→            metadata.len()
416→        ));
417→    }
418→
419→    if replace_all {
420→        if !content.contains(old_str) {
421→            return Err(format!("Text not found in {file_path}"));
422→        }
423→        let new_content = content.replace(old_str, new_str);
424→        let count = content.matches(old_str).count();
425→        std::fs::write(path, &new_content).map_err(|e| format!("Cannot write file: {e}"))?;
426→        return Ok(format!("Replaced {count} occurrences in {file_path}"));
427→    }
428→
429→    // Single exact match
430→    let count = content.matches(old_str).count();
431→    if count == 0 {
432→        return Err(format!("Text not found in {file_path}"));
433→    }
434→    if count > 1 {
435→        return Err(format!(
436→            "Found {count} matches in {file_path} (expected exactly 1). Use replace_all=true for bulk replacement."
437→        ));
438→    }
439→
440→    let new_content = content.replacen(old_str, new_str, 1);
441→    std::fs::write(path, &new_content).map_err(|e| format!("Cannot write file: {e}"))?;
442→
443→    Ok(format!("Edited {file_path}"))
444→}
