446→fn grep_exec(input: &Value) -> Result<String, String> {
447→    let pattern = input["pattern"]
448→        .as_str()
449→        .ok_or("Missing required parameter: pattern")?;
450→    let path = input["path"].as_str().unwrap_or(".");
451→    let file_type = input["file_type"].as_str();
452→    let case_sensitive = input["case_sensitive"].as_bool().unwrap_or(true);
453→
454→    // Check rg is installed
455→    let rg_check = Command::new("which").arg("rg").output();
456→    match rg_check {
457→        Ok(output) if !output.status.success() => {
458→            return Err(
459→                "ripgrep (rg) is not installed. Install it with: brew install ripgrep (macOS) or apt install ripgrep (Linux)"
460→                    .to_string(),
461→            );
462→        }
463→        Err(_) => {
464→            return Err(
465→                "ripgrep (rg) is not installed. Install it with: brew install ripgrep (macOS) or apt install ripgrep (Linux)"
466→                    .to_string(),
467→            );
468→        }
469→        _ => {}
470→    }
471→
472→    let mut cmd = Command::new("rg");
473→    cmd.arg("--max-count=50")
474→        .arg("--line-number")
475→        .arg("--no-heading")
476→        .arg("--color=never");
477→
478→    if !case_sensitive {
479→        cmd.arg("-i");
480→    }
481→
482→    if let Some(ft) = file_type {
483→        cmd.arg("--type").arg(ft);
484→    }
485→
486→    cmd.arg(pattern).arg(path);
487→
488→    let output = cmd.output().map_err(|e| format!("Failed to run rg: {e}"))?;
489→
490→    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
491→    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
492→
493→    if !output.status.success() {
494→        let code = output.status.code().unwrap_or(-1);
495→        if code == 1 {
496→            // rg exit 1 = no matches
497→            return Ok("No matches found".to_string());
498→        }
499→        if !stderr.is_empty() {
500→            return Err(stderr.trim().to_string());
501→        }
502→        return Err(format!("rg exited with code {code}"));
503→    }
504→
505→    let result = stdout.trim().to_string();
506→    if result.is_empty() {
507→        Ok("No matches found".to_string())
508→    } else {
509→        Ok(result)
510→    }
511→}
